css:
.ring-spinner {
  width: 40px; height: 40px;
  border-radius: 50%;
  border: 3px solid rgba(255,255,255,0.1);
  border-top-color: #B8FB3C;
  animation: ring-spin 0.7s linear infinite;
}
@keyframes ring-spin { to { transform: rotate(360deg); } }

.bounce-dots {
  display: flex;
  align-items: center;
  gap: 6px;
}
.bounce-dots div {
  width: 10px; height: 10px;
  border-radius: 50%;
  background: #B8FB3C;
  animation: dot-bounce 1.2s ease infinite;
}
.bounce-dots div:nth-child(2) { animation-delay: 0.2s; }
.bounce-dots div:nth-child(3) { animation-delay: 0.4s; }
@keyframes dot-bounce {
  0%, 80%, 100% { transform: scale(0.4); opacity: 0.4; }
  40% { transform: scale(1); opacity: 1; }
}

.progress-bar {
  width: 200px; height: 4px;
  background: rgba(255,255,255,0.1);
  border-radius: 2px;
  overflow: hidden;
}
.progress-fill {
  height: 100%;
  border-radius: 2px;
  background: linear-gradient(to right, #B8FB3C, #06b6d4);
  animation: progress-move 1.8s ease-in-out infinite;
}
@keyframes progress-move {
  0% { transform: scaleX(0) translateX(0); }
  50% { transform: scaleX(1) translateX(0); }
  100% { transform: scaleX(0) translateX(200px); }
}

.pulse-ring {
  width: 40px; height: 40px;
  border-radius: 50%;
  background: rgba(184,251,60,0.3);
  animation: pulse-expand 1.5s ease-out infinite;
}
@keyframes pulse-expand {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(2); opacity: 0; }
}

.orbit-loader {
  position: relative;
  width: 44px; height: 44px;
  border-radius: 50%;
  border: 2px solid rgba(255,255,255,0.1);
  animation: orbit-spin 1.5s linear infinite;
}
.planet {
  position: absolute;
  width: 10px; height: 10px;
  background: #B8FB3C;
  border-radius: 50%;
  top: -6px; left: 50%; transform: translateX(-50%);
}
@keyframes orbit-spin { to { transform: rotate(360deg); } }

.skel-line {
  height: 14px;
  border-radius: 6px;
  background: rgba(255,255,255,0.07);
  margin-bottom: 10px;
  overflow: hidden;
  position: relative;
}
.skel-line::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.08), transparent);
  animation: shimmer-scan 1.4s infinite;
}
@keyframes shimmer-scan {
  from { transform: translateX(-100%); }
  to { transform: translateX(100%); }
}

.eq-bars {
  display: flex;
  align-items: flex-end;
  gap: 4px;
  height: 36px;
}
.eq-bars div {
  width: 6px;
  background: #B8FB3C;
  border-radius: 3px 3px 0 0;
  animation: eq-animate 1s ease infinite;
}
.eq-bars div:nth-child(1) { animation-delay: 0s; height: 60%; }
.eq-bars div:nth-child(2) { animation-delay: 0.1s; height: 100%; }
.eq-bars div:nth-child(3) { animation-delay: 0.2s; height: 40%; }
.eq-bars div:nth-child(4) { animation-delay: 0.3s; height: 80%; }
.eq-bars div:nth-child(5) { animation-delay: 0.4s; height: 60%; }
@keyframes eq-animate {
  0%, 100% { transform: scaleY(0.4); }
  50% { transform: scaleY(1); }
}

.ripple-loader {
  position: relative;
  width: 50px; height: 50px;
}
.ripple-loader div {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 3px solid #B8FB3C;
  animation: ripple-out 1.5s cubic-bezier(0,0.2,0.8,1) infinite;
}
.ripple-loader div:nth-child(2) { animation-delay: -0.75s; }
@keyframes ripple-out {
  0% { transform: scale(0); opacity: 1; }
  100% { transform: scale(1); opacity: 0; }
}

.gradient-ring {
  width: 44px; height: 44px;
  border-radius: 50%;
  background: conic-gradient(#B8FB3C 0%, #a855f7 40%, transparent 40%);
  animation: gradient-ring-spin 1s linear infinite;
  mask: radial-gradient(farthest-side, transparent calc(100% - 4px), #fff calc(100% - 4px));
  -webkit-mask: radial-gradient(farthest-side, transparent calc(100% - 4px), #fff calc(100% - 4px));
}
@keyframes gradient-ring-spin { to { transform: rotate(360deg); } }

.shimmer-card {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.06);
  border-radius: 14px;
  overflow: hidden;
}
.shimmer-img { height: 80px; background: rgba(255,255,255,0.07); position: relative; overflow: hidden; }
.shimmer-body { padding: 12px; }
.s-line {
  height: 10px;
  border-radius: 5px;
  background: rgba(255,255,255,0.07);
  margin-bottom: 8px;
  position: relative;
  overflow: hidden;
}
.s-line.full { width: 100%; }
.s-line.half { width: 60%; }
.shimmer-img::after, .s-line::after {
  content: '';
  position: absolute; inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.08), transparent);
  animation: shimmer-scan 1.4s infinite;
}
@keyframes shimmer-scan {
  from { transform: translateX(-100%); }
  to { transform: translateX(100%); }
}

.typing-dots {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 10px 16px;
  background: rgba(255,255,255,0.06);
  border-radius: 50px;
}
.typing-dots span {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: rgba(255,255,255,0.4);
  animation: typing-jump 1.4s ease infinite;
}
.typing-dots span:nth-child(2) { animation-delay: 0.2s; }
.typing-dots span:nth-child(3) { animation-delay: 0.4s; }
@keyframes typing-jump {
  0%, 60%, 100% { transform: translateY(0); }
  30% { transform: translateY(-6px); }
}

.dual-ring { position: relative; width: 44px; height: 44px; }
.dual-ring::before, .dual-ring::after {
  content: '';
  position: absolute;
  border-radius: 50%;
}
.dual-ring::before {
  inset: 0;
  border: 3px solid transparent;
  border-top-color: #B8FB3C;
  animation: ring-spin 0.8s linear infinite;
}
.dual-ring::after {
  inset: 6px;
  border: 3px solid transparent;
  border-bottom-color: #a855f7;
  animation: ring-spin 1.2s linear infinite reverse;
}
@keyframes ring-spin { to { transform: rotate(360deg); } }

.loading-text { color: rgba(255,255,255,0.7); font-size: 15px; font-family: monospace; }
.dots::after {
  content: '';
  animation: loading-dots 1.5s steps(4,end) infinite;
}
@keyframes loading-dots {
  0% { content: ''; }
  25% { content: '.'; }
  50% { content: '..'; }
  75% { content: '...'; }
  100% { content: ''; }
}

.circular-progress { width: 50px; height: 50px; transform: rotate(-90deg); }
.bg-circle { fill: none; stroke: rgba(255,255,255,0.1); stroke-width: 3; }
.progress-circle {
  fill: none;
  stroke: #B8FB3C;
  stroke-width: 3;
  stroke-linecap: round;
  stroke-dasharray: 113;
  stroke-dashoffset: 113;
  animation: circle-progress 2s ease-in-out infinite;
}
@keyframes circle-progress {
  0% { stroke-dashoffset: 113; }
  50% { stroke-dashoffset: 30; }
  100% { stroke-dashoffset: 113; }
}

.wifi-loader {
  position: relative;
  width: 40px; height: 40px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
}
.wifi-loader div {
  position: absolute;
  border-radius: 50%;
  border: 3px solid rgba(255,255,255,0.1);
  border-top-color: transparent;
  border-bottom-color: transparent;
  border-left-color: transparent;
  animation: wifi-arc 1.5s ease infinite;
}
.wifi-loader div:nth-child(1) { width: 12px; height: 12px; border-right-color: #B8FB3C; animation-delay: 0s; }
.wifi-loader div:nth-child(2) { width: 24px; height: 24px; border-right-color: #B8FB3C; animation-delay: 0.2s; }
.wifi-loader div:nth-child(3) { width: 36px; height: 36px; border-right-color: #B8FB3C; animation-delay: 0.4s; }
@keyframes wifi-arc {
  0%, 100% { opacity: 0.2; }
  50% { opacity: 1; }
}
